    while (x > 0) {
        count += x & 1;
        x >>= 1;
    }
    return count;
}

int getDepth(long long x) {
    if (x == 1) return 0;
    int depth = 0;
    while (x != 1) {
        x = popcount(x);
        depth++;
    }
    return depth;
}

long long solve(long long n, long long k) {
    if (k == 0) {
        return (n >= 1 && getDepth(1) == k) ? 1 : 0;
    }
    long long count = 0;
    for (long long x = 1; x <= n; x++) {
        if (getDepth(x) == k) {
            count++;
        }
    }
    return count;
}

